import { useEffect, useMemo, useState } from "react";
import { MapContainer, Marker, Popup, TileLayer } from "react-leaflet";
import {
  CartesianGrid,
  Line,
  LineChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis
} from "recharts";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import markerIcon2x from "leaflet/dist/images/marker-icon-2x.png";
import markerIcon from "leaflet/dist/images/marker-icon.png";
import markerShadow from "leaflet/dist/images/marker-shadow.png";

delete L.Icon.Default.prototype._getIconUrl;

L.Icon.Default.mergeOptions({
  iconRetinaUrl: markerIcon2x,
  iconUrl: markerIcon,
  shadowUrl: markerShadow
});

function getWeatherMultiplier(weather) {
  if (weather === "Sunny") return 1.2;
  if (weather === "Cloudy") return 0.8;
  if (weather === "Rainy") return 0.55;
  return 1;
}

function runEnergyDecisionEngine(homes, weather, gridLoad) {
  const weatherMultiplier = getWeatherMultiplier(weather);

  const analyzedHomes = homes.map((home) => {
    const generated = Number(home.generatedPower || 0) * weatherMultiplier;
    const consumed = Number(home.consumedPower || 0);
    const battery = Number(home.batteryLevel || 0);
    const netEnergy = generated - consumed;

    let aiRole = "BALANCED";
    let aiDecision = "Maintain current energy usage";

    if (netEnergy > 1.5 && battery > 60) {
      aiRole = "SELLER";
      aiDecision = "Sell surplus renewable energy to nearby buyers";
    } else if (netEnergy > 0 && battery <= 60) {
      aiRole = "STORAGE";
      aiDecision = "Store surplus energy in battery";
    } else if (netEnergy < -1) {
      aiRole = "BUYER";
      aiDecision = "Buy renewable energy from local sellers";
    }

    return {
      ...home,
      adjustedGeneratedPower: Number(generated.toFixed(2)),
      netEnergy: Number(netEnergy.toFixed(2)),
      aiRole,
      aiDecision
    };
  });

  const sellers = analyzedHomes.filter((home) => home.aiRole === "SELLER");
  const buyers = analyzedHomes.filter((home) => home.aiRole === "BUYER");

  let energyPrice = 6;
  if (buyers.length > sellers.length) energyPrice += 2;
  if (sellers.length > buyers.length) energyPrice -= 1;
  if (gridLoad > 80) energyPrice += 3;
  energyPrice = Math.max(energyPrice, 3);

  const totalGenerated = Number(
    analyzedHomes.reduce((sum, home) => sum + home.adjustedGeneratedPower, 0).toFixed(2)
  );

  const totalConsumed = Number(
    analyzedHomes.reduce((sum, home) => sum + Number(home.consumedPower || 0), 0).toFixed(2)
  );

  const carbonSaved = Number((totalGenerated * 0.7).toFixed(2));
  const renewablePercentage =
    totalConsumed > 0 ? Number(((totalGenerated / totalConsumed) * 100).toFixed(1)) : 0;

  const blackoutPrevented = gridLoad > 85 && sellers.length > 0;

  return {
    homes: analyzedHomes,
    sellers,
    buyers,
    energyPrice,
    totalGenerated,
    totalConsumed,
    carbonSaved,
    renewablePercentage,
    blackoutPrevented,
    gridStatus: blackoutPrevented
      ? "AI PREVENTED OVERLOAD"
      : totalGenerated >= totalConsumed
      ? "GRID OPERATING EFFICIENTLY"
      : "HIGH GRID LOAD DETECTED"
  };
}

function App() {
  const [homes, setHomes] = useState([]);
  const [trades, setTrades] = useState([]);
  const [chartData, setChartData] = useState([]);
  const [predictions, setPredictions] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [weather, setWeather] = useState("Sunny");
  const [gridLoad, setGridLoad] = useState(72);

  const engine = useMemo(
    () => runEnergyDecisionEngine(homes, weather, gridLoad),
    [homes, weather, gridLoad]
  );

  useEffect(() => {
    const fetchEnergy = () => {
      fetch("http://localhost:5000/energy")
        .then((res) => res.json())
        .then((data) => {
          const incomingHomes = data.homes || [];

          setHomes(incomingHomes);
          setTrades(data.trades || []);
          setPredictions(data.predictions || []);
          setAlerts(data.alerts || []);

          setChartData((prev) => [
            ...prev.slice(-9),
            {
              time: new Date().toLocaleTimeString(),
              generated: data.grid?.totalGenerated || 0,
              consumed: data.grid?.totalConsumed || 0
            }
          ]);
        })
        .catch((error) => {
          console.error("Energy API error:", error);
        });
    };

    fetchEnergy();
    const interval = setInterval(fetchEnergy, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen bg-black text-white p-8">
      <h1 className="text-5xl font-bold text-green-400 mb-10 text-center">
        OpenGreenGrid Dashboard
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
        <Card title="Total Homes" value={engine.homes.length} color="cyan" />
        <Card title="AI Energy Sellers" value={engine.sellers.length} color="green" />
        <Card title="AI Energy Buyers" value={engine.buyers.length} color="red" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
        <div className="bg-gray-900 border border-yellow-400 rounded-2xl p-6">
          <h2 className="text-xl font-bold text-yellow-300">Weather Impact</h2>
          <select
            value={weather}
            onChange={(e) => setWeather(e.target.value)}
            className="mt-4 w-full bg-black border border-yellow-400 p-3 rounded-xl"
          >
            <option>Sunny</option>
            <option>Cloudy</option>
            <option>Rainy</option>
          </select>
        </div>

        <div className="bg-gray-900 border border-blue-400 rounded-2xl p-6">
          <h2 className="text-xl font-bold text-blue-300">Grid Load</h2>
          <input
            type="range"
            min="30"
            max="100"
            value={gridLoad}
            onChange={(e) => setGridLoad(Number(e.target.value))}
            className="w-full mt-5"
          />
          <p className="text-3xl font-bold mt-3">{gridLoad}%</p>
        </div>

        <Card title="Carbon Saved" value={`${engine.carbonSaved} kg`} color="emerald" small />
        <Card title="Energy Price" value={`₹${engine.energyPrice}/kWh`} color="pink" small />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {engine.homes.map((home, index) => (
          <div key={index} className="bg-gray-900 border border-green-500 rounded-2xl p-6 shadow-lg">
            <h2 className="text-3xl font-semibold mb-2 text-green-300">{home.house}</h2>
            <p className="text-cyan-300 mb-4">{home.area}</p>
            <Info label="Generated" value={`${home.generatedPower} kWh`} color="green" />
            <Info label="Weather Adjusted" value={`${home.adjustedGeneratedPower} kWh`} color="cyan" />
            <Info label="Consumed" value={`${home.consumedPower} kWh`} color="yellow" />
            <Info label="Battery" value={`${home.batteryLevel}%`} color="blue" />
            <Info label="Carbon Saved" value={`${home.carbonSaved} kg`} color="emerald" />
            <Info label="Efficiency" value={`${home.efficiencyScore}%`} color="pink" />

            <div className="p-3 rounded-xl text-center font-bold text-lg bg-gray-800 mt-4">
              {home.status}
            </div>

            <div className="mt-4 bg-black border border-cyan-500 rounded-xl p-4">
              <p className="text-cyan-300 font-bold">AI Role: {home.aiRole}</p>
              <p className="text-sm mt-2">{home.aiDecision}</p>
              <p className="text-sm mt-2">
                Net Energy:{" "}
                <span className={home.netEnergy >= 0 ? "text-green-400" : "text-red-400"}>
                  {home.netEnergy} kWh
                </span>
              </p>
            </div>
          </div>
        ))}
      </div>

      <Section title="Autonomous DeFi Energy Trades" color="cyan">
        {trades.length === 0 ? (
          <div className="bg-gray-900 p-4 rounded-xl text-gray-400">No active trades currently</div>
        ) : (
          trades.map((trade, index) => (
            <div key={index} className="bg-cyan-900 border border-cyan-400 p-5 rounded-xl mb-4">
              <p className="text-xl">
                <b>{trade.from}</b> ({trade.fromArea}) sold{" "}
                <b className="text-cyan-300">{trade.energy} kWh</b> to{" "}
                <b>{trade.to}</b> ({trade.toArea})
              </p>
              <p className="text-cyan-300 mt-2">
                Price: ₹{trade.price}/kWh | Hash: {trade.transactionHash}
              </p>
            </div>
          ))
        )}
      </Section>

      <Section title="Real-Time Energy Analytics" color="purple">
        <div className="bg-gray-900 p-6 rounded-2xl border border-purple-500">
          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="time" />
              <YAxis />
              <Tooltip />
              <Line type="monotone" dataKey="generated" stroke="#00ff88" strokeWidth={3} />
              <Line type="monotone" dataKey="consumed" stroke="#ff4444" strokeWidth={3} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </Section>

      <Section title="Smart City Energy Map" color="green">
        <div className="rounded-2xl overflow-hidden border border-green-500">
          <MapContainer center={[28.6139, 77.209]} zoom={11} style={{ height: "500px", width: "100%" }}>
            <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
            {engine.homes.map((home, index) => (
              <Marker key={index} position={[home.latitude, home.longitude]}>
                <Popup>
                  <div>
                    <h2>{home.house}</h2>
                    <p>Area: {home.area}</p>
                    <p>Generated: {home.adjustedGeneratedPower} kWh</p>
                    <p>Consumed: {home.consumedPower} kWh</p>
                    <p>Battery: {home.batteryLevel}%</p>
                    <p>Status: {home.status}</p>
                    <p>AI Role: {home.aiRole}</p>
                  </div>
                </Popup>
              </Marker>
            ))}
          </MapContainer>
        </div>
      </Section>

      <Section title="Smart Grid Health" color="blue">
        <div className="bg-gray-900 border border-blue-500 rounded-2xl p-8">
          <Info label="Total Generated Energy" value={`${engine.totalGenerated} kWh`} color="green" />
          <Info label="Total Consumed Energy" value={`${engine.totalConsumed} kWh`} color="yellow" />
          <Info label="Renewable Percentage" value={`${engine.renewablePercentage}%`} color="emerald" />
          <Info label="Grid Status" value={engine.gridStatus} color="cyan" />
          {engine.blackoutPrevented && (
            <p className="text-green-400 text-xl mt-4 font-bold">
              AI rerouted surplus renewable energy and prevented overload.
            </p>
          )}
        </div>
      </Section>

      <Section title="AI Prediction Engine" color="orange">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {predictions.map((item, index) => (
            <div key={index} className="bg-gray-900 border border-orange-500 rounded-2xl p-6">
              <h3 className="text-2xl font-bold text-orange-300">{item.house} - {item.area}</h3>
              <p className="text-lg font-semibold mt-3">{item.prediction}</p>
            </div>
          ))}
        </div>
      </Section>

      <Section title="Smart Grid Alerts" color="red">
        {alerts.length === 0 ? (
          <div className="bg-gray-900 p-5 rounded-xl text-gray-400">No critical alerts detected</div>
        ) : (
          alerts.map((alert, index) => (
            <div key={index} className="bg-red-900 border border-red-500 p-5 rounded-xl mb-4 animate-pulse">
              <p className="text-xl font-bold">{alert.house} - {alert.area}</p>
              <p className="text-lg mt-2">{alert.message}</p>
            </div>
          ))
        )}
      </Section>
    </div>
  );
}

function Card({ title, value, color, small }) {
  return (
    <div className={`bg-gray-900 border border-${color}-400 rounded-2xl p-6 text-center shadow-lg`}>
      <h2 className={`text-xl font-bold text-${color}-300`}>{title}</h2>
      <p className={`${small ? "text-4xl" : "text-5xl"} font-bold mt-4`}>{value}</p>
    </div>
  );
}

function Info({ label, value, color }) {
  return (
    <p className="text-lg mb-2">
      {label}: <span className={`text-${color}-400 font-bold`}>{value}</span>
    </p>
  );
}

function Section({ title, color, children }) {
  return (
    <div className="mt-12">
      <h2 className={`text-4xl font-bold text-${color}-400 mb-6`}>{title}</h2>
      {children}
    </div>
  );
}

export default App;
